create table pob_tracking (
    id          number(*, 0)
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 nocache
        noorder nocycle nokeep noscale
    not null enable,
    datum       date default sysdate,
    app_id      number(*, 0),
    app_page_id number(*, 0),
    app_session varchar2(100 byte),
    request     varchar2(100 byte),
    scope       varchar2(100 byte),
    extra       varchar2(4000 byte),
    task        number(*, 0)
);

alter table pob_tracking
    add constraint pob_tracking_pk primary key ( id )
        using index enable;


